import { hmac, md5, sha256, randomBytes } from 'k6/crypto';
import encoding from 'k6/encoding';
import http from 'k6/http';
import { check, sleep } from 'k6';

const BASE_URL = 'https://quickpizza.grafana.com';
const SECRET   = 'my-signing-secret';

export const options = {
  vus: 3,
  duration: '20s',
  thresholds: {
    http_req_duration: ['p(95)<500'],
    checks:            ['rate>0.99'],
  },
};

export default function () {
  // ── Unique request ID ─────────────────────────────────────────────────
  const reqId = encoding.b64encode(randomBytes(16));

  // ── Request body + HMAC signature ─────────────────────────────────────
  const body = JSON.stringify({ action: 'get_quotes', ts: Date.now() });
  const signature = hmac('sha256', SECRET, body, 'hex');

  // ── MD5 content hash (e.g. for ETag / integrity checks) ───────────────
  const contentHash = md5(body, 'hex');

  // ── Basic Auth via base64 ─────────────────────────────────────────────
  const credentials = encoding.b64encode('apiuser:apipassword');

  // ── SHA-256 password hash example ─────────────────────────────────────
  const passwordHash = sha256('userpassword', 'hex');

  const res = http.get(`${BASE_URL}/api/quotes`, {
    headers: {
      'X-Request-ID':   reqId,
      'X-Signature':    signature,
      'X-Content-Hash': contentHash,
      'Authorization':  `Basic ${credentials}`,
    },
  });

  check(res, {
    'status 200':      (r) => r.status === 200,
    'req-id non-empty': () => reqId.length > 0,
    'sig non-empty':    () => signature.length > 0,
  });

  // ── Decode example ────────────────────────────────────────────────────
  const decoded = encoding.b64decode(reqId, 'rawurl', 's');
  console.log(`VU ${__VU} | reqId_len=${reqId.length} | hash=${contentHash.substring(0, 8)}...`);

  sleep(1);
}
